+function pairMatches(pair: RelationPair, target: Entity): boolean {
+    const pairTarget = pair[$internal].target;
+    return pairTarget === '*' || pairTarget === target;
+}
+
+function pairKey(pair: RelationPair, target: Entity): string {
+    const relationId = pair[$internal].relation[$internal].trait.id;
+    return `${relationId}:${pair[$internal].target === '*' ? target : pair[$internal].target}`;
+}
+
+function pairGroupMatches(pairs: RelationPair[], tracked: Set<string>, logic: 'and' | 'or'): boolean {
+    if (logic === 'or') return tracked.size > 0;
+    return pairs.every((pair) => {
+        const prefix = `${pair[$internal].relation[$internal].trait.id}:`;
+        return pair[$internal].target === '*'
+            ? [...tracked].some((key) => key.startsWith(prefix))
+            : tracked.has(pairKey(pair, pair[$internal].target as Entity));
+    });
+}
+
+function isOppositePairEvent(groupType: EventType, eventType: EventType): boolean {
+    return (groupType === 'add' && eventType === 'remove') ||
+        (groupType === 'remove' && eventType === 'add') ||
+        (groupType === 'change' && (eventType === 'add' || eventType === 'remove'));
+}
