+/** Notify tracking queries of a concrete relation-target structural event. */
+export function setPairTracking(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: 'add' | 'remove'
+) {
+    const instance = getTraitInstance(world[$internal].traitInstances, trait);
+    if (!instance) return;
+    const { generationId, bitflag } = instance;
+
+    for (const query of instance.trackingQueries) {
+        const match = query.checkTracking(world, entity, eventType, generationId, bitflag, target);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
